import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"27. Top Of Band Payment","description":"","frontmatter":{"title":"27. Top Of Band Payment","eba":"Biomedical Engineers 2025-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/wages/27-top-of-band-payment.md","filePath":"ebas/biomedical-engineers/wages/27-top-of-band-payment.md"}'),s={name:"ebas/biomedical-engineers/wages/27-top-of-band-payment.md"};function p(i,e,r,l,d,m){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_27-top-of-band-payment" tabindex="-1">27. Top Of Band Payment <a class="header-anchor" href="#_27-top-of-band-payment" aria-label="Permalink to &quot;27. Top Of Band Payment&quot;">​</a></h1><p><strong>27.1</strong> Eligibility To be eligible for a Top of Band Payment:</p><p><strong>(a)</strong> An Employee must have been classified at the highest pay point within their class (see subclause 27.2(d)) for one full anniversary period; and</p><p><strong>(b)</strong> The Employee must have given satisfactory performance over the preceding 12 months.</p><p>Example: An Employee was appointed to Class 3 Year 3 on 1 May 2024. The Employee’s anniversary date is 1 May 2025. On 1 May 2025, the Employee will be entitled to the Top of Band Payment provided that the Employee has given satisfactory performance between 1 May 2024 and 30 April 2025.</p><p><strong>27.2</strong> Top of Band Payments</p><p><strong>(a)</strong> A Top of Band Payment is in addition to the wage rates specified in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>.</p><p><strong>(b)</strong> A Top of Band Payment will be paid as an annual gross lump sum paid on the FFPPOOA the anniversary date of the Employee’s appointment to the highest pay point within their current class.</p><p><strong>(c)</strong> The amount of the Top of Band Payment is as follows: Anniversary date in the year Amount commencing FFPPOOA 1 August 2024 $2060.00</p><p>1 August 2025 $2121.80</p><p>1 August 2026 $2185.45</p><p>1 August 2027 and each 1 August $2251.02 thereafter</p><p><strong>(d)</strong> A Top of Band Payment only applies to the following classifications: Classification</p><p>Class 2 Pay Point 2 Class 3 Pay Point 3 Class 4 Pay Point 3 Class 5 Pay Point 3*</p><p>*From FFPPOOA commencement of the Agreement.</p>',15)])])}const h=a(s,[["render",p]]);export{y as __pageData,h as default};
